import type { Request, Response } from 'express';
import { productService } from '@services/products';
import { rejectResponse, successResponse } from '@utils/response';
import { extractId, extractPagination, extractStringList } from '@utils/helpers-request';
import type { SearchProductsRequest } from '@types';
import type { CastError } from 'mongoose';
import { emitAnalyticsEvent, AnalyticsEvent } from '@utils/analytics';

/**
 * Query parameters generated by the search form (they are the same as SearchOrdersRequest keys)
 */
export type IGetProductsQuery = Partial<Record<keyof SearchProductsRequest, string>>;

/**
 * GET /products
 * POST /products/search
 * List/search products via query parameters or request body.
 * Admin sees all products (including inactive/deleted); public sees only active ones.
 */
export const getProducts = (
    request: Request<{ id?: string }, unknown, SearchProductsRequest, IGetProductsQuery>,
    response: Response
) => {
    const { page, pageSize } = extractPagination({
        page: request.body?.page ?? request.query.page,
        pageSize: request.body?.pageSize ?? request.query.pageSize
    });

    const minPriceRaw = request.body?.minPrice ?? request.query.minPrice;
    const maxPriceRaw = request.body?.maxPrice ?? request.query.maxPrice;
    const categoryRaw = request.body?.category ?? request.query.category;
    const tagRaw = request.body?.tag ?? request.query.tag;
    // OpenAPI currently models category/tag as single-value filters; if arrays are provided we pick the first one.
    const category = extractStringList(categoryRaw)[0];
    const tag = extractStringList(tagRaw)[0];

    return productService
        .search(
            {
                id: extractId(request.params.id, request.body?.id, request.query.id),
                page,
                pageSize,
                text: request.body?.text ?? request.query.text,
                minPrice: minPriceRaw ? Number(minPriceRaw) : undefined,
                maxPrice: maxPriceRaw ? Number(maxPriceRaw) : undefined,
                category,
                tag
            },
            request.user?.admin === true
        )
        .then((result) => {
            emitAnalyticsEvent({
                distinctId: request.user?.id ?? 'anonymous',
                event: AnalyticsEvent.PRODUCTS_SEARCHED,
                traceId: request.traceContext?.traceId,
                properties: {
                    text: request.body?.text ?? request.query.text,
                    page,
                    pageSize,
                    result_count: (result as { list?: unknown[] })?.list?.length ?? 0,
                },
            });
            successResponse(response, result);
        })
        .catch((error: CastError) => {
            rejectResponse(response, 500, 'Unknown Error', [error.message]);
        });
};
